import { contextBridge, ipcRenderer } from 'electron';
console.log('Preload script is loading...');
contextBridge.exposeInMainWorld('electronAPI', {
    createTab: (tabId, url) => ipcRenderer.invoke('create-tab', tabId, url),
    navigateTab: (tabId, url) => ipcRenderer.invoke('navigate-tab', tabId, url),
    switchTab: (tabId) => ipcRenderer.invoke('switch-tab', tabId),
    closeTab: (tabId) => ipcRenderer.invoke('close-tab', tabId),
    goBack: (tabId) => ipcRenderer.invoke('go-back', tabId),
    goForward: (tabId) => ipcRenderer.invoke('go-forward', tabId),
    reload: (tabId) => ipcRenderer.invoke('reload', tabId),
    onTabLoading: (callback) => {
        ipcRenderer.on('tab-loading', (_, tabId) => callback(tabId));
    },
    onTabLoaded: (callback) => {
        ipcRenderer.on('tab-loaded', (_, tabId, url) => callback(tabId, url));
    },
    onTabFailed: (callback) => {
        ipcRenderer.on('tab-failed', (_, tabId, errorCode, errorDescription) => callback(tabId, errorCode, errorDescription));
    },
    onTabTitleUpdated: (callback) => {
        ipcRenderer.on('tab-title-updated', (_, tabId, title) => callback(tabId, title));
    },
    onTabFaviconUpdated: (callback) => {
        ipcRenderer.on('tab-favicon-updated', (_, tabId, faviconUrl) => callback(tabId, faviconUrl));
    },
    removeAllListeners: (channel) => {
        ipcRenderer.removeAllListeners(channel);
    }
});
